
"use client";
import { useState, useEffect } from "react";
import { PlusCircle, Monitor, Eye, Building, ArrowLeft } from 'lucide-react';
import { getLabsAction, addLabAction, getRoomsAction, addRoomAction, getPcsAction, getLabRequestsAction, getUsersAction } from "@/app/actions/dbActions";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { Lab, Room, Pc, LabRequest, User } from "@/utils/storage";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
  DialogClose
} from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Wifi, WifiOff, Clock } from 'lucide-react';

function LabDetailView({ lab, onBack }: { lab: Lab, onBack: () => void }) {
    const [pcs, setPcs] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            if (!lab) return;
            setLoading(true);
            try {
                const allPcs = await getPcsAction();
                const labPcs = allPcs.filter(pc => pc.labId === lab.id);
                const requests = await getLabRequestsAction();
                const users = await getUsersAction();
                const now = new Date();

                const pcsWithStatus = labPcs.map(pc => {
                    const activeRequest = requests.find(r => 
                        r.pcId === pc.id && 
                        r.status === 'approved' &&
                        now >= new Date(r.startTime) &&
                        now <= new Date(r.endTime)
                    );
                    const user = activeRequest ? users.find(u => u.id === activeRequest.studentId) : null;

                    return {
                        ...pc,
                        status: activeRequest ? 'occupied' : 'available',
                        currentUser: user,
                        currentRequest: activeRequest
                    };
                });
                
                setPcs(pcsWithStatus.sort((a,b) => parseInt(a.pcNumber) - parseInt(b.pcNumber)));
            } catch (e) {
                console.error(e);
                toast.error("Failed to load lab details.");
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, [lab]);

    return (
        <div>
            <div className="mb-8">
                <Button onClick={onBack} variant="ghost" className="mb-4"><ArrowLeft className="mr-2 h-4 w-4" /> Back to Labs</Button>
                <h1 className="text-3xl font-bold text-gray-800">{lab?.name}</h1>
                <p className="text-muted-foreground">Real-time PC status overview</p>
            </div>

            {loading ? <p>Loading PCs...</p> : (
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8 gap-4">
                    {pcs.map(pc => (
                        <Card key={pc.id} className={`shadow-sm hover:shadow-lg transition-shadow border-2 ${pc.status === 'occupied' ? 'border-red-200 bg-red-50/50' : 'border-green-200 bg-green-50/50'}`}>
                            <CardHeader className="flex flex-row items-center justify-between pb-2">
                                <CardTitle className="text-sm font-medium flex items-center gap-2">
                                    <Monitor className={`h-4 w-4 ${pc.status === 'occupied' ? 'text-red-500' : 'text-green-600'}`} />
                                    PC #{pc.pcNumber}
                                </CardTitle>
                                {pc.status === 'occupied' ? <WifiOff className="h-4 w-4 text-red-500"/> : <Wifi className="h-4 w-4 text-green-600"/> }
                            </CardHeader>
                            <CardContent>
                                <div className="text-lg font-bold capitalize">
                                    {pc.status}
                                </div>
                                {pc.status === 'occupied' && pc.currentUser && (
                                    <div className="mt-2 pt-2 border-t border-red-100 text-xs text-red-900">
                                        <p className="font-bold truncate">{pc.currentUser.name}</p>
                                        <p className="text-red-900/70">{pc.currentUser.id}</p>
                                        <p className="flex items-center gap-1 mt-1 text-red-900/70">
                                            <Clock className="h-3 w-3"/> 
                                            {new Date(pc.currentRequest.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        </p>
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )}
        </div>
    );
}

export default function LabManagement() {
    const [labs, setLabs] = useState<Lab[]>([]);
    const [rooms, setRooms] = useState<Room[]>([]);
    const [newLabName, setNewLabName] = useState('');
    const [newLabCapacity, setNewLabCapacity] = useState('');
    const [isAddLabOpen, setAddLabOpen] = useState(false);
    
    const [newRoomName, setNewRoomName] = useState('');
    const [newRoomCapacity, setNewRoomCapacity] = useState('');
    const [isAddRoomOpen, setAddRoomOpen] = useState(false);
    
    const [activeTab, setActiveTab] = useState("labs");
    const [selectedLab, setSelectedLab] = useState<Lab | null>(null);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLabs(await getLabsAction());
        setRooms(await getRoomsAction());
    };

    const handleAddLab = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newLabName || !newLabCapacity) {
            toast.error("Please provide lab name and capacity.");
            return;
        }
        await addLabAction({
            id: `LAB-${Date.now()}`,
            name: newLabName,
            capacity: parseInt(newLabCapacity, 10),
        });
        toast.success("Lab and its PCs have been added successfully.");
        setNewLabName('');
        setNewLabCapacity('');
        fetchData();
        setAddLabOpen(false);
    };

    const handleAddRoom = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newRoomName || !newRoomCapacity) {
            toast.error("Please provide room name and capacity.");
            return;
        }
        await addRoomAction({
            id: `ROOM-${Date.now()}`,
            name: newRoomName,
            capacity: parseInt(newRoomCapacity, 10),
        });
        toast.success("Room has been added successfully.");
        setNewRoomName('');
        setNewRoomCapacity('');
        fetchData();
        setAddRoomOpen(false);
    };
    
    if (selectedLab) {
        return <LabDetailView lab={selectedLab} onBack={() => setSelectedLab(null)} />
    }

    return (
        <div>
            <div className="flex justify-between items-start mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-gray-800">Lab Management</h1>
                    <p className="text-muted-foreground">Manage labs and rooms.</p>
                </div>
                {activeTab === 'labs' && (
                    <Dialog open={isAddLabOpen} onOpenChange={setAddLabOpen}>
                        <DialogTrigger asChild>
                            <Button className="bg-primary hover:bg-primary/90 text-white">
                                <PlusCircle className="mr-2 h-4 w-4"/> Add Lab
                            </Button>
                        </DialogTrigger>
                        <DialogContent>
                            <DialogHeader>
                                <DialogTitle>Add New LAB</DialogTitle>
                            </DialogHeader>
                            <form onSubmit={handleAddLab} className="space-y-4 pt-4">
                                <div className="space-y-2">
                                    <Label htmlFor="labName">LAB Name</Label>
                                    <Input id="labName" value={newLabName} onChange={e => setNewLabName(e.target.value)} placeholder="e.g., Computer Lab 1"/>
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor="labCapacity">Capacity (PCs)</Label>
                                    <Input id="labCapacity" type="number" value={newLabCapacity} onChange={e => setNewLabCapacity(e.target.value)} placeholder="e.g., 30"/>
                                </div>
                                <DialogFooter>
                                    <DialogClose asChild><Button type="button" variant="secondary">Cancel</Button></DialogClose>
                                    <Button type="submit" className="bg-primary hover:bg-primary/90 text-white">Add LAB</Button>
                                </DialogFooter>
                            </form>
                        </DialogContent>
                    </Dialog>
                )}
                {activeTab === 'rooms' && (
                    <Dialog open={isAddRoomOpen} onOpenChange={setAddRoomOpen}>
                        <DialogTrigger asChild>
                            <Button className="bg-primary hover:bg-primary/90 text-white">
                                <PlusCircle className="mr-2 h-4 w-4"/> Add Room
                            </Button>
                        </DialogTrigger>
                        <DialogContent>
                            <DialogHeader>
                                <DialogTitle>Add New Room</DialogTitle>
                            </DialogHeader>
                            <form onSubmit={handleAddRoom} className="space-y-4 pt-4">
                                <div className="space-y-2">
                                    <Label htmlFor="roomName">Room Name</Label>
                                    <Input id="roomName" value={newRoomName} onChange={e => setNewRoomName(e.target.value)} placeholder="e.g., Room 101"/>
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor="roomCapacity">Capacity (People)</Label>
                                    <Input id="roomCapacity" type="number" value={newRoomCapacity} onChange={e => setNewRoomCapacity(e.target.value)} placeholder="e.g., 50"/>
                                </div>
                                <DialogFooter>
                                    <DialogClose asChild><Button type="button" variant="secondary">Cancel</Button></DialogClose>
                                    <Button type="submit" className="bg-primary hover:bg-primary/90 text-white">Add Room</Button>
                                </DialogFooter>
                            </form>
                        </DialogContent>
                    </Dialog>
                )}
            </div>
            
            <Tabs defaultValue="labs" className="w-full" onValueChange={(value) => setActiveTab(value)}>
                <TabsList className="bg-transparent p-0 h-auto mb-6 gap-2">
                    <TabsTrigger value="labs" className="data-[state=active]:bg-primary data-[state=active]:text-white rounded-md">Labs</TabsTrigger>
                    <TabsTrigger value="rooms" className="data-[state=active]:bg-primary data-[state=active]:text-white rounded-md">Rooms</TabsTrigger>
                </TabsList>
                <TabsContent value="labs">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {labs.map(lab => (
                            <Card key={lab.id} className="bg-white">
                                <CardHeader>
                                    <CardTitle className="flex items-center gap-2 text-gray-800">
                                        <Monitor className="text-primary"/>
                                        {lab.name}
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <p className="text-muted-foreground">Capacity: {lab.capacity} PCs</p>
                                    <Button onClick={() => setSelectedLab(lab)} className="w-full bg-blue-600 hover:bg-blue-700 text-white">
                                        <Eye className="mr-2 h-4 w-4"/> View PCs
                                    </Button>
                                </CardContent>
                            </Card>
                        ))}
                        {labs.length === 0 && <p className="text-muted-foreground col-span-full text-center">No LABs configured yet.</p>}
                    </div>
                </TabsContent>
                <TabsContent value="rooms">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {rooms.map(room => (
                            <Card key={room.id} className="bg-white">
                                <CardHeader>
                                    <CardTitle className="flex items-center gap-2 text-gray-800">
                                        <Building className="text-primary"/>
                                        {room.name}
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <p className="text-muted-foreground">Capacity: {room.capacity} people</p>
                                </CardContent>
                            </Card>
                        ))}
                        {rooms.length === 0 && <p className="text-muted-foreground col-span-full text-center">No rooms configured yet.</p>}
                    </div>
                </TabsContent>
            </Tabs>
        </div>
    );
}
